EXAMPLE_REQUEST.code_example:
String value = new String("A");
int number = 1;
assert value instanceof String && number == 1;

int[] arr = {10, 20, 30};
int length = arr.length;
assert length == 3;

final int limit = 3;
int result = limit * 2;
assert result == 6;

java.util.List<String> branches = new java.util.ArrayList<>();
int selected = 2;
branches.add(switch (selected) { case 1 -> "A"; default -> "B"; });
assert branches.get(0).equals("B");

class Parent { int value = 7; }
class Child extends Parent {}
assert new Child().value == 7;

java.util.function.Predicate<Integer> positive = value -> value > 0;
java.util.List<Integer> values = new java.util.ArrayList<>();
values.add(1);
assert positive.test(values.get(0));

java.util.List<Integer> values = java.util.List.of(3, 1, 2);
java.util.List<Integer> result = values.stream().filter(v -> v > 1).sorted().collect(java.util.stream.Collectors.toList());
assert result.get(0) == 2 && result.size() == 2;

Object value = new String("ABC");
Class<?> type = value.getClass();
java.lang.reflect.Method method = type.getMethod("length");
int length = (int) method.invoke(value);
assert length == 3;

def add(left, right):
    return left + right
assert add(2, 3) == 5

a, b = 'ABC', 'AC'
dp = [[0] * (len(b) + 1) for _ in range(len(a) + 1)]
for i in range(1, len(a) + 1):
    for j in range(1, len(b) + 1): dp[i][j] = dp[i-1][j-1] + 1 if a[i-1] == b[j-1] else max(dp[i-1][j], dp[i][j-1])
assert dp[-1][-1] == 2

buckets = [[] for _ in range(2)]
for key in (1, 3): buckets[key % 2].append(key)
assert buckets[1] == [1, 3]

edges = [('S', 'A', 4), ('S', 'B', 5), ('A', 'B', -2)]
distance = {'S': 0, 'A': float('inf'), 'B': float('inf')}
for _ in range(2):
    for u, v, w in edges: distance[v] = min(distance[v], distance[u] + w)
assert distance['B'] == 2
